sections.example:
def greet(name):
    return f"Hello, {name}!"

def add(a, b):
    return a + b

print(greet("Alice"))  # Hello, Alice!
print(add(3, 7))       # 10

def is_even(n):
    return n % 2 == 0

print(is_even(4))      # True

def power(base, exp=2):
    return base ** exp

print(power(3))      # 9  (uses default exp=2)
print(power(3, 3))   # 27 (overrides to exp=3)

def total(*args):
    return sum(args)

print(total(1, 2, 3))       # 6
print(total(10, 20, 30, 40)) # 100
